revision.text:
{{TemplateData header}}
<templatedata>
{
	"description": "This template is used to start formatting for a reference list or bibliography. ",
	"params": {
		"1": {
			"label": "Column width/Columns",
			"type": "string",
			"description": "Width for the reference list columns in units of em. For example: '30em'. If spaced as '30 em', it will not be recognized. Secondary mode (deprecated): integer number of fixed columns.",
			"example": "30em",
			"default": "1",
			"suggested": true
		},
		"colwidth": {
			"label": "Column width",
			"description": "Width of columns, for example, '25em'. The default is '30em'.",
			"type": "string",
			"required": false,
			"default": "30em"
		},
		"indent": {
			"label": "Hanging indentation",
			"type": "string",
			"description": "Set to \"yes\" to use hanging indents for the contained references."
		}
	},
	"format": "inline"
}
</templatedata>

